// src/pages/Categories.js
import { useEffect, useState } from "react";
import {
  collection,
  getDocs,
  addDoc,
  deleteDoc,
  doc,
  updateDoc,
} from "firebase/firestore";
import { db } from "../firebase/config";
import { useNavigate } from "react-router-dom";
import Modal from "../components/Modal";

const EMPTY_FORM = { name: "", imageUrl: "" };

const Categories = () => {
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [form, setForm] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();

  const fetchCategories = async () => {
    setLoading(true);
    const snap = await getDocs(collection(db, "categories"));
    setCategories(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
    setLoading(false);
  };

  useEffect(() => {
    fetchCategories();
  }, []);

  const openAdd = () => {
    setEditTarget(null);
    setForm(EMPTY_FORM);
    setModalOpen(true);
  };

  const openEdit = (e, cat) => {
    e.stopPropagation();
    setEditTarget(cat);
    setForm({ name: cat.name, imageUrl: cat.imageUrl });
    setModalOpen(true);
  };

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      if (editTarget) {
        await updateDoc(doc(db, "categories", editTarget.id), form);
        setCategories((prev) =>
          prev.map((c) => (c.id === editTarget.id ? { ...c, ...form } : c))
        );
      } else {
        const ref = await addDoc(collection(db, "categories"), form);
        setCategories((prev) => [...prev, { id: ref.id, ...form }]);
      }
      setModalOpen(false);
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (e, id) => {
    e.stopPropagation();
    if (!window.confirm("هل تريد حذف هذا الصنف؟")) return;
    await deleteDoc(doc(db, "categories", id));
    setCategories((prev) => prev.filter((c) => c.id !== id));
  };

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h1 className="page-title">الأصناف</h1>
          <p className="page-desc">إدارة أصناف القائمة</p>
        </div>
        <button className="btn-primary" onClick={openAdd}>
          + إضافة صنف
        </button>
      </div>

      {loading ? (
        <div className="loading-state">
          <div className="loader" />
        </div>
      ) : categories.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">◈</div>
          <p>لا توجد أصناف بعد</p>
          <button className="btn-primary" onClick={openAdd}>
            أضف أول صنف
          </button>
        </div>
      ) : (
        <div className="grid grid-4">
          {categories.map((cat) => (
            <div
              key={cat.id}
              className="cat-card"
              onClick={() =>
                navigate(`/dashboard/products/${cat.name}`)
              }
            >
              <div className="cat-img-wrap">
                {cat.imageUrl ? (
                  <img
                    src={cat.imageUrl}
                    alt={cat.name}
                    className="cat-img"
                    onError={(e) => {
                      e.target.style.display = "none";
                      e.target.nextSibling.style.display = "flex";
                    }}
                  />
                ) : null}
                <div
                  className="cat-img-fallback"
                  style={{ display: cat.imageUrl ? "none" : "flex" }}
                >
                  ◈
                </div>
              </div>
              <div className="cat-body">
                <h3 className="cat-name">{cat.name}</h3>
                <div className="cat-actions">
                  <button
                    className="btn-icon edit"
                    onClick={(e) => openEdit(e, cat)}
                    title="تعديل"
                  >
                    ✎
                  </button>
                  <button
                    className="btn-icon del"
                    onClick={(e) => handleDelete(e, cat.id)}
                    title="حذف"
                  >
                    ✕
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      <Modal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        title={editTarget ? "تعديل الصنف" : "إضافة صنف جديد"}
      >
        <form onSubmit={handleSave}>
          <div className="form-group">
            <label className="form-label">اسم الصنف</label>
            <input
              className="form-input"
              placeholder="مثال: برغر، بيتزا..."
              value={form.name}
              onChange={(e) => setForm({ ...form, name: e.target.value })}
              required
            />
          </div>
          <div className="form-group">
            <label className="form-label">رابط الصورة</label>
            <input
              className="form-input"
              placeholder="https://..."
              value={form.imageUrl}
              onChange={(e) =>
                setForm({ ...form, imageUrl: e.target.value })
              }
              dir="ltr"
            />
          </div>
          <div className="modal-actions">
            <button
              type="button"
              className="btn-ghost"
              onClick={() => setModalOpen(false)}
            >
              إلغاء
            </button>
            <button type="submit" className="btn-primary" disabled={saving}>
              {saving ? <span className="btn-loader" /> : "حفظ"}
            </button>
          </div>
        </form>
      </Modal>
    </div>
  );
};

export default Categories;
